# flux/replication_manager.py\n\nimport hashlib\nimport json\nimport time\nfrom typing import Dict, Any, List, Optional\n\nclass ReplicationManager:\n    """\n    Manages data replication and consistency across the distributed JSON mesh.\n\n    This component is responsible for ensuring data integrity and availability\n    by synchronizing changes across multiple nodes, handling conflict resolution,\n    and maintaining a consistent state for all registered data segments.\n    """\n\n    def __init__(self, node_id: str, data_store_interface: Any, network_client: Any, consistency_model: str = "eventual"):\n        """\n        Initializes the ReplicationManager.\n\n        Args:\n            node_id (str): Unique identifier for the current node.\n            data_store_interface (Any): An interface to interact with the local data store.\n            network_client (Any): A client for communicating with other nodes in the mesh.\n            consistency_model (str): The consistency model to adhere to (e.g., "eventual", "strong").\n        """\n        self.node_id = node_id\n        self.data_store = data_store_interface\n        self.network_client = network_client\n        self.consistency_model = consistency_model\n        self._replication_log: List[Dict[str, Any]] = []\n        self._last_sync_timestamps: Dict[str, float] = {}\n        print(f"[{self.node_id}] ReplicationManager initialized with model: {self.consistency_model}")\n\n    def _generate_data_hash(self, data: Dict[str, Any]) -> str:\n        """Generates a consistent SHA256 hash for a given JSON data object."""\n        # Ensure consistent serialization for hashing\n        serialized_data = json.dumps(data, sort_keys=True, separators=(',', ':'))\n        return hashlib.sha256(serialized_data.encode('utf-8')).hexdigest()\n\n    def record_local_change(self, key: str, value: Dict[str, Any], operation: str, timestamp: float) -> None:\n        """\n        Records a local data modification for replication.\n\n        Args:\n            key (str): The key of the data segment.\n            value (Dict[str, Any]): The new value of the data segment.\n            operation (str): The type of operation ("CREATE", "UPDATE", "DELETE").\n            timestamp (float): Unix timestamp of the operation.\n        """\n        change_record = {\n            "node_id": self.node_id,\n            "key": key,\n            "value_hash": self._generate_data_hash(value) if value else None,\n            "value": value, # Store value for potential direct application\n            "operation": operation,\n            "timestamp": timestamp,\n            "version": self._get_next_version(key) # Simple versioning for conflict resolution\n        }\n        self._replication_log.append(change_record)\n        print(f"[{self.node_id}] Recorded local change: {operation} on {key} at {timestamp}")\n\n    def _get_next_version(self, key: str) -> int:\n        """Retrieves the current version of a key from the data store and increments it."""\n        current_data = self.data_store.get(key)\n        return (current_data.get("metadata", {}).get("version", 0) + 1) if current_data else 1\n\n    async def replicate_changes(self, target_node_id: Optional[str] = None) -> None:\n        """\n        Pushes local changes to other nodes in the mesh.\n\n        Args:\n            target_node_id (Optional[str]): If specified, only replicates to this node.\n                                            Otherwise, replicates to all known peers.\n        """\n        changes_to_replicate = self._replication_log[:] # Get a snapshot\n        if not changes_to_replicate:\n            print(f"[{self.node_id}] No changes to replicate.")\n            return\n\n        peers = self.network_client.get_active_peers()\n        if target_node_id:\n            peers = [peer for peer in peers if peer['id'] == target_node_id]\n\n        for peer in peers:\n            if peer['id'] == self.node_id:\n                continue # Do not replicate to self\n\n            try:\n                print(f"[{self.node_id}] Initiating replication to {peer['id']}...")\n                # In a real system, this would be an async network call\n                # For simplicity, we'll simulate a direct call or message queue interaction\n                await self.network_client.send_replication_data(\n                    peer['id'],\n                    {"source_node": self.node_id, "changes": changes_to_replicate}\n                )\n                self._last_sync_timestamps[peer['id']] = time.time()\n                print(f"[{self.node_id}] Successfully replicated {len(changes_to_replicate)} changes to {peer['id']}.")\n            except Exception as e:\n                print(f"[{self.node_id}] Error replicating to {peer['id']}: {e}")\n\n        # Clear the replication log after successful replication to all targeted peers\n        # In a more robust system, this would be done per-peer confirmation\n        self._replication_log.clear()\n\n    async def receive_replication_data(self, replication_payload: Dict[str, Any]) -> None:\n        """\n        Processes incoming replication data from another node.\n\n        Args:\n            replication_payload (Dict[str, Any]): The payload containing changes from a source node.\n                                                Expected format: {"source_node": str, "changes": List[Dict]}\n        """\n        source_node = replication_payload.get("source_node")\n        incoming_changes = replication_payload.get("changes", [])\n\n        if not source_node or not incoming_changes:\n            print(f"[{self.node_id}] Received invalid replication payload.")\n            return\n\n        print(f"[{self.node_id}] Received {len(incoming_changes)} changes from {source_node}.")\n\n        for change in incoming_changes:\n            key = change["key"]\n            incoming_value = change["value"]\n            incoming_operation = change["operation"]\n            incoming_timestamp = change["timestamp"]\n            incoming_version = change.get("version", 0)\n\n            local_data = self.data_store.get(key)\n            local_version = local_data.get("metadata", {}).get("version", 0) if local_data else 0\n\n            if self.consistency_model == "eventual":\n                # Last-Writer-Wins (LWW) based on timestamp\n                if local_data is None or incoming_timestamp > local_data.get("metadata", {}).get("timestamp", 0):\n                    self._apply_change(key, incoming_value, incoming_operation, incoming_timestamp, incoming_version)\n                elif incoming_timestamp == local_data.get("metadata", {}).get("timestamp", 0):\n                    # If timestamps are equal, use version or node_id for tie-breaking\n                    if incoming_version > local_version:\n                         self._apply_change(key, incoming_value, incoming_operation, incoming_timestamp, incoming_version)\n                    elif incoming_version == local_version and source_node > self.node_id: # Arbitrary tie-breaker\n                         self._apply_change(key, incoming_value, incoming_operation, incoming_timestamp, incoming_version)\n                    else:\n                        print(f"[{self.node_id}] Conflict detected for {key} (timestamps equal, local version/node wins). Ignoring incoming change from {source_node}.")\n                else:\n                    print(f"[{self.node_id}] Incoming change for {key} from {source_node} is older than local. Ignoring.")\n            elif self.consistency_model == "strong":\n                # Placeholder for strong consistency logic (e.g., Paxos, Raft integration)\n                # This would involve quorum consensus and more complex state machine replication.\n                print(f"[{self.node_id}] Strong consistency model requires consensus protocol. Incoming change for {key} from {source_node} deferred.")\n                pass # Defer to a consensus protocol handler\n            else:\n                print(f"[{self.node_id}] Unknown consistency model: {self.consistency_model}")\n\n    def _apply_change(self, key: str, value: Dict[str, Any], operation: str, timestamp: float, version: int) -> None:\n        """Applies a validated change to the local data store."""\n        metadata = {\n            "timestamp": timestamp,\n            "version": version,\n            "last_modified_node": self.node_id # This node is applying it\n        }\n        if operation == "CREATE" or operation == "UPDATE":\n            self.data_store.set(key, {"data": value, "metadata": metadata})\n            print(f"[{self.node_id}] Applied {operation} for {key}.")\n        elif operation == "DELETE":\n            self.data_store.delete(key)\n            print(f"[{self.node_id}] Applied {operation} for {key}.")\n        else:\n            print(f"[{self.node_id}] Unknown operation '{operation}' for {key}.")\n\n    def get_replication_status(self) -> Dict[str, Any]:\n        """Returns the current replication status and metrics."""\n        return {\n            "node_id": self.node_id,\n            "pending_local_changes": len(self._replication_log),\n            "last_sync_with_peers": self._last_sync_timestamps,\n            "consistency_model": self.consistency_model\n        }\n\n# Example Usage (assuming a simple data store and network client interface)\nif __name__ == "__main__":\n    class MockDataStore:\n        def __init__(self):\n            self._data = {}\n\n        def get(self, key: str) -> Optional[Dict[str, Any]]:\n            return self._data.get(key)\n\n        def set(self, key: str, value: Dict[str, Any]) -> None:\n            self._data[key] = value\n            print(f"[MockDataStore] Set key '{key}'")\n\n        def delete(self, key: str) -> None:\n            if key in self._data:\n                del self._data[key]\n                print(f"[MockDataStore] Deleted key '{key}'")\n\n    class MockNetworkClient:\n        def __init__(self, node_id: str, peers: List[Dict[str, str]]):\n            self.node_id = node_id\n            self._peers = peers\n            self.replication_managers: Dict[str, ReplicationManager] = {} # For direct simulation\n\n        def get_active_peers(self) -> List[Dict[str, str]]:\n            return [p for p in self._peers if p['id'] != self.node_id]\n\n        async def send_replication_data(self, target_node_id: str, payload: Dict[str, Any]) -> None:\n            print(f"[MockNetworkClient] Node {self.node_id} sending data to {target_node_id}: {payload['changes'][0]['key']}...")\n            if target_node_id in self.replication_managers:\n                await self.replication_managers[target_node_id].receive_replication_data(payload)\n            else:\n                print(f"[MockNetworkClient] Target node {target_node_id} not found for direct simulation.")\n\n    import asyncio\n\n    async def main():\n        # Setup mock components for Node A and Node B\n        data_store_a = MockDataStore()\n        data_store_b = MockDataStore()\n\n        peers_config = [{"id": "node-A"}, {"id": "node-B"}]\n\n        network_client_a = MockNetworkClient("node-A", peers_config)\n        network_client_b = MockNetworkClient("node-B", peers_config)\n\n        replication_manager_a = ReplicationManager("node-A", data_store_a, network_client_a)\n        replication_manager_b = ReplicationManager("node-B", data_store_b, network_client_b)\n\n        # Register managers with mock network clients for direct simulation\n        network_client_a.replication_managers["node-B"] = replication_manager_b\n        network_client_b.replication_managers["node-A"] = replication_manager_a\n\n        # Node A makes a change\n        print("\n--- Node A creates data ---")\n        current_time = time.time()\n        replication_manager_a.record_local_change("user:1", {"name": "Alice", "email": "alice@example.com"}, "CREATE", current_time)\n        await replication_manager_a.replicate_changes()\n\n        await asyncio.sleep(0.1) # Simulate network delay\n\n        print("\n--- Node B state after A's replication ---")\n        print(f"Node B data for user:1: {data_store_b.get('user:1')}")\n\n        # Node B makes a change (update)\n        print("\n--- Node B updates data ---")\n        current_time = time.time() + 1 # Later timestamp\n        replication_manager_b.record_local_change("user:1", {"name": "Alicia", "email": "alicia@example.com", "status": "active"}, "UPDATE", current_time)\n        await replication_manager_b.replicate_changes()\n\n        await asyncio.sleep(0.1)\n\n        print("\n--- Node A state after B's replication ---")\n        print(f"Node A data for user:1: {data_store_a.get('user:1')}")\n\n        # Node A makes a conflicting change (older timestamp)\n        print("\n--- Node A makes an older conflicting change ---")\n        old_time = time.time() - 5 # Older timestamp\n        replication_manager_a.record_local_change("user:1", {"name": "Old Alice", "email": "old_alice@example.com"}, "UPDATE", old_time)\n        await replication_manager_a.replicate_changes()\n\n        await asyncio.sleep(0.1)\n\n        print("\n--- Node B state after A's older conflicting replication ---")\n        # Node B should ignore this older change due to LWW\n        print(f"Node B data for user:1: {data_store_b.get('user:1')}")\n\n\n    asyncio.run(main())